arguments.command:
# Get better detail on the SGen worker addresses using nm to find enclosing symbols
nm /tmp/mono_debug.dbg 2>/dev/null | sort | awk -v a1=0x2f4b20 -v a2=0x2f4c84 '
  { addr = strtonum("0x" $1) }
  addr <= strtonum(a1) { prev1 = $0; prevaddr1 = addr }
  addr <= strtonum(a2) { prev2 = $0; prevaddr2 = addr }
  addr > strtonum(a1) && !done1 { printf "0x2f4b20 in: %s (+0x%x)\n", prev1, strtonum(a1)-prevaddr1; done1=1 }
  addr > strtonum(a2) && !done2 { printf "0x2f4c84 in: %s (+0x%x)\n", prev2, strtonum(a2)-prevaddr2; done2=1 }
' | head -5

