arguments.command:
# Search for function entries that contain address range around 0x2f4xxx
readelf -s /tmp/mono_debug.dbg 2>/dev/null | awk '
$4 == "FUNC" {
  addr = strtonum("0x" substr($2, length($2)-15))
  size = strtonum("0x" $3) 
  if (addr <= 0x2f4b20 && (addr + size) > 0x2f4b20) {
    printf "0x2f4b20 in: %s (0x%x+0x%x, offset=0x%x)\n", $8, addr, size, 0x2f4b20-addr
  }
  if (addr <= 0x2f4c84 && (addr + size) > 0x2f4c84) {
    printf "0x2f4c84 in: %s (0x%x+0x%x, offset=0x%x)\n", $8, addr, size, 0x2f4c84-addr
  }
}'

